import {createElement} from '../render.js';

function createSelectedOffersTemplate(offersList) {
  let template = '';
  offersList.forEach((element) => {
    console.log(element);
    template = `${template}
    <li class="event__offer">
      <span class="event__offer-title">${element.title}</span>
      &plus;&euro;&nbsp;
      <span class="event__offer-price">${element.price}</span>
    </li>
    `;
  });
  console.log(template);
  return template;
}

function createNewTripPointTemplate(point, destination, offersList) {
  const { basePrice, type, isFavorite } = point;
  const { name } = destination;
  let favorite = 'event__favorite-btn--active';

  if (!isFavorite) {
    favorite = '';
  }
  return `
  <li class="trip-events__item">
    <div class="event">
      <time class="event__date" datetime="2019-03-18">MAR 18</time>
      <div class="event__type">
        <img class="event__type-icon" width="42" height="42" src="img/icons/${type}.png" alt="Event type icon">
      </div>
      <h3 class="event__title">${type} ${name}</h3>
      <div class="event__schedule">
        <p class="event__time">
          <time class="event__start-time" datetime="2019-03-18T12:25">16:20</time>
          &mdash;
          <time class="event__end-time" datetime="2019-03-18T13:35">17:00</time>
        </p>
        <p class="event__duration">40M</p>
      </div>
      <p class="event__price">
        &euro;&nbsp;<span class="event__price-value">${basePrice}</span>
      </p>
      <h4 class="visually-hidden">Offers:</h4>
      <ul class="event__selected-offers">
        ${createSelectedOffersTemplate(offersList)}
      </ul>
      <button class="event__favorite-btn ${favorite}" type="button">
        <span class="visually-hidden">Add to favorite</span>
        <svg class="event__favorite-icon" width="28" height="28" viewBox="0 0 28 28">
          <path d="M14 21l-8.22899 4.3262 1.57159-9.1631L.685209 9.67376 9.8855 8.33688 14 0l4.1145 8.33688 9.2003 1.33688-6.6574 6.48934 1.5716 9.1631L14 21z"/>
        </svg>
      </button>
      <button class="event__rollup-btn" type="button">
        <span class="visually-hidden">Open event</span>
      </button>
    </div>
  </li>
`;
}

class TripPointView {
  constructor({point, destination, offersList}) {
    this.point = point;
    this.destination = destination;
    this.offersList = offersList;
  }

  getTemplate() {
    return createNewTripPointTemplate(this.point, this.destination, this.offersList);
  }

  getElement() {
    if (!this.element) {
      this.element = createElement(this.getTemplate());
    }

    return this.element;
  }

  removeElement() {
    this.element = null;
  }
}

export { TripPointView };
